                                items.forEach(item => {
                                    const btn = item.querySelector('.toto-question');
                                    const answer = item.querySelector('.toto-answer');
                                    const icon = item.querySelector('.toto-icon');

                                    btn.addEventListener('click', () => {
                                        const isActive = item.classList.contains('active');

                                        items.forEach(otherItem => {
                                            otherItem.classList.remove('active');
                                            otherItem.querySelector('.toto-answer').style.maxHeight = null;
                                            otherItem.querySelector('.toto-icon').innerText = '+';
                                        });
                                        if (!isActive) {
                                            item.classList.add('active');
                                            answer.style.maxHeight = answer.scrollHeight + "px";
                                            icon.innerText = '-';
                                        }
                                    });
                                });
                            });
